-- TEE-20: Booking class selector with friendly names
-- Creates course_booking_classes table and seeds with data from ForeUp + Chronogolf

-- Step 1: Create table
CREATE TABLE course_booking_classes (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  course_id uuid NOT NULL REFERENCES courses(id) ON DELETE CASCADE,
  platform_booking_class_id text NOT NULL,
  name text NOT NULL,
  is_default boolean NOT NULL DEFAULT false,
  is_protected boolean NOT NULL DEFAULT false,
  created_at timestamptz DEFAULT now()
);

CREATE UNIQUE INDEX idx_cbc_course_class
  ON course_booking_classes (course_id, platform_booking_class_id);
CREATE INDEX idx_cbc_course_id ON course_booking_classes (course_id);

ALTER TABLE course_booking_classes ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Booking classes are publicly readable"
  ON course_booking_classes FOR SELECT USING (true);

-- Step 2: Seed ForeUp booking classes
ON CONFLICT DO NOTHING;

-- Step 3: Seed Chronogolf booking classes
ON CONFLICT DO NOTHING;